```java
import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        if (n == 0) return 0;
        Arrays.sort(nums);
        long max_len = 1;
        for (int i = 0; i < n; ++i) {
            long target = nums[i] * k;
            int low = i;
            int high = n - 1;
            int best = i - 1;
            while (low <= high) {
                int mid = (low + high) / 2;
                if (nums[mid] <= target) {
                    best = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            int len;
            if (best >= i) {
                len = best - i + 1;
            } else {
                len = 1;
            }
            if (len > max_len) {
                max_len = len;
            }
        }
        return n - max_len;
    }
}
```

